        Union<inferredOutput, c>,
        input
      >
    : MatchEach<i, o, handledCases, Union<inferredOutput, c>, input>;

  tap(
    callback: (result: PickReturnValue<o, inferredOutput>) => unknown
  ): MatchEach<i, o, handledCases, inferredOutput, input>;

  otherwise<c>(
    handler: (value: input) => PickReturnValue<o, c>
  ): Results<o, Union<inferredOutput, c>>;

  exhaustive: DeepExcludeAll<i, handledCases> extends infer remaining
    ? [remaining] extends [never]
      ? Exhaustive<o, inferredOutput>
      : NonExhaustiveError<remaining>
    : never;

  run(): Results<o, inferredOutput>;

  returnType: [inferredOutput] extends [never]
    ? <output>() => MatchEach<i, output, handledCases, never, input>
    : TSPatternError<'calling `.returnType<T>()` is only allowed directly after `matchEach(...)`.'>;

  narrow(): MatchEach<
    DeepExcludeAll<i, handledCases>,
    o,
    [],
    inferredOutput,
    DeepExcludeAll<i, handledCases>
  >;

  toFunction(): (value: input) => Results<o, inferredOutput>;
  toPartialFunction(): (value: input) => Results<o, inferredOutput> | undefined;
  toExhaustiveFunction: DeepExcludeAll<i, handledCases> extends infer remaining
    ? [remaining] extends [never]
      ? () => (value: input) => Results<o, inferredOutput>
      : NonExhaustiveError<remaining>
    : never;
};

type DeepExcludeAll<a, tupleList extends any[]> = [a] extends [never]
  ? never
  : tupleList extends [infer excluded, ...infer tail]
  ? DeepExcludeAll<DeepExclude<a, excluded>, tail>
  : a;

